// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MilestoneMarket is ReentrancyGuard {
    address public immutable token;
    uint256 public immutable threshold;
    uint256 public immutable deadline;
    address public immutable creator;

    bool public resolved;
    bool public reached;

    mapping(address => uint256) public deposits;
    uint256 public totalDeposited;

    event Deposited(address indexed user, uint256 amount);
    event Resolved(bool reached);
    event RefundWithdrawn(address indexed user, uint256 amount);

    constructor(
        address _token,
        uint256 _threshold,
        uint256 _deadline,
        address _creator
    ) {
        require(_deadline > block.timestamp, "Deadline in past");
        require(_threshold > IERC20(_token).totalSupply(), "Threshold must exceed current supply");

        token = _token;
        threshold = _threshold;
        deadline = _deadline;
        creator = _creator;
    }

    // 🟢 Deposit ETH to participate
    function deposit() external payable nonReentrant {
        require(block.timestamp < deadline, "Market ended");
        require(!resolved, "Already resolved");
        require(msg.value > 0, "Zero deposit");

        deposits[msg.sender] += msg.value;
        totalDeposited += msg.value;

        emit Deposited(msg.sender, msg.value);
    }

    // 🔍 Check bonding curve condition (totalSupply based)
    function checkMilestone() public view returns (bool) {
        uint256 supply = IERC20(token).totalSupply();
        return supply >= threshold;
    }

    // 🟡 Resolve after deadline
    function resolve() external {
        require(block.timestamp >= deadline, "Not ended");
        require(!resolved, "Already resolved");

        reached = checkMilestone();
        resolved = true;

        emit Resolved(reached);
    }

    // 🔴 Refund if milestone NOT reached
    function withdrawRefund() external nonReentrant {
        require(resolved, "Not resolved");
        require(!reached, "Milestone reached");

        uint256 amount = deposits[msg.sender];
        require(amount > 0, "Nothing to withdraw");

        deposits[msg.sender] = 0;

        payable(msg.sender).transfer(amount);

        emit RefundWithdrawn(msg.sender, amount);
    }
}

